export class AddEditComponent implements OnInit {
  form!: UntypedFormGroup;
  id!: string;
  isAddMode!: boolean;
  loading = false;
  submitted = false;

  constructor(
    private formBuilder: UntypedFormBuilder,
    private route: ActivatedRoute,
    private router: Router,
    private accountService: AccountService,
    private alertService: AlertService
  ) { }

  ngOnInit() {
    this.id = this.route.snapshot.params['id'];
    this.isAddMode = !this.id;

    const passwordValidators = [Validators.minLength(6)];
    if (this.isAddMode) passwordValidators.push(Validators.required);

    this.form = this.formBuilder.group({
      title: ['', Validators.required],
      firstName: ['', Validators.required],
      lastName: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      role: ['', Validators.required],
      password: ['', passwordValidators],
      confirmPassword: ['']
    }, { validators: MustMatch('password', 'confirmPassword') });

    if (!this.isAddMode) {
      this.accountService.getById(this.id)
        .pipe(first())
        .subscribe(account => this.form.patchValue(account));
    }
  }

  get f() { return this.form.controls; }

  onSubmit() {
    this.submitted = true;
    this.alertService.clear();
    if (this.form.invalid) return;
    this.loading = true;
    if (this.isAddMode) {
      this.createAccount();
    } else {
      this.updateAccount();
    }
  }

  private createAccount() {
    this.accountService.create(this.form.value)
      .pipe(first())
      .subscribe({
        next: () => {
          this.alertService.success('Account created successfully', { keepAfterRouteChange: true });
          this.router.navigate(['/admin/accounts']);
        },
        error: (error: string) => {
          this.alertService.error(error, { id: 'add-edit-alert' });
          this.loading = false;
        }
      });
  }

  private updateAccount() {
    this.accountService.update(this.id, this.form.value)
      .pipe(first())
      .subscribe({
        next: () => {
          this.alertService.success('Account updated successfully', { keepAfterRouteChange: true });
          this.router.navigate(['/admin/accounts']);
        },
        error: (error: string) => {
          this.alertService.error(error, { id: 'add-edit-alert' });
          this.loading = false;
        }
      });
  }
}
<h4>{{isAddMode ? 'Add Account' : 'Edit Account'}}</h4>
<alert id="add-edit-alert"></alert>
<form [formGroup]="form" (ngSubmit)="onSubmit()">
  <div class="mb-3">
    <label class="form-label">Title</label>
    <select formControlName="title" class="form-select" [ngClass]="{ 'is-invalid': submitted && f['title'].errors }">
      <option value=""></option>
      <option value="Mr">Mr</option>
      <option value="Mrs">Mrs</option>
      <option value="Miss">Miss</option>
      <option value="Ms">Ms</option>
    </select>
    <div *ngIf="submitted && f['title'].errors" class="invalid-feedback">Title is required</div>
  </div>
  <div class="mb-3">
    <label class="form-label">First Name</label>
    <input type="text" formControlName="firstName" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['firstName'].errors }" />
    <div *ngIf="submitted && f['firstName'].errors" class="invalid-feedback">First Name is required</div>
  </div>
  <div class="mb-3">
    <label class="form-label">Last Name</label>
    <input type="text" formControlName="lastName" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['lastName'].errors }" />
    <div *ngIf="submitted && f['lastName'].errors" class="invalid-feedback">Last Name is required</div>
  </div>
  <div class="mb-3">
    <label class="form-label">Email</label>
    <input type="text" formControlName="email" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['email'].errors }" />
    <div *ngIf="submitted && f['email'].errors" class="invalid-feedback">
      <div *ngIf="f['email'].errors['required']">Email is required</div>
      <div *ngIf="f['email'].errors['email']">Email must be a valid email address</div>
    </div>
  </div>
  <div class="mb-3">
    <label class="form-label">Role</label>
    <select formControlName="role" class="form-select" [ngClass]="{ 'is-invalid': submitted && f['role'].errors }">
      <option value=""></option>
      <option value="User">User</option>
      <option value="Admin">Admin</option>
    </select>
    <div *ngIf="submitted && f['role'].errors" class="invalid-feedback">Role is required</div>
  </div>
  <div class="mb-3">
    <label class="form-label">Password
      <em *ngIf="!isAddMode">(Leave blank to keep current password)</em>
    </label>
    <input type="password" formControlName="password" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['password'].errors }" />
    <div *ngIf="submitted && f['password'].errors" class="invalid-feedback">
      <div *ngIf="f['password'].errors['required']">Password is required</div>
      <div *ngIf="f['password'].errors['minlength']">Password must be at least 6 characters</div>
    </div>
  </div>
  <div class="mb-3">
    <label class="form-label">Confirm Password</label>
    <input type="password" formControlName="confirmPassword" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['confirmPassword'].errors }" />
    <div *ngIf="submitted && f['confirmPassword'].errors" class="invalid-feedback">
      <div *ngIf="f['confirmPassword'].errors['required']">Confirm Password is required</div>
      <div *ngIf="f['confirmPassword'].errors['mustMatch']">Passwords must match</div>
    </div>
  </div>
  <div class="d-flex justify-content-between">
    <button [disabled]="loading" class="btn btn-primary">
      <span *ngIf="loading" class="spinner-border spinner-border-sm me-1"></span>
      Save
    </button>
    <a routerLink="/admin/accounts" class="btn btn-link">Cancel</a>
  </div>
</form>
